    private const val DEFAULT_SVG = """<svg width="20" height="20" viewBox="0 0 20 20" fill="white"><rect x="1" y="1" width="7.5" height="7.5" rx="2"/><rect x="11.5" y="1" width="7.5" height="7.5" rx="2"/><rect x="1" y="11.5" width="7.5" height="7.5" rx="2"/><rect x="11.5" y="11.5" width="7.5" height="7.5" rx="2"/></svg>"""

    fun resolveFabIcon(fabIcon: String): String {
        if (fabIcon.isBlank()) return DEFAULT_SVG
        if (fabIcon.startsWith("custom:")) {
            val base64 = fabIcon.removePrefix("custom:")
            return """<img src="data:image/png;base64,$base64" width="28" height="28" style="border-radius:50%;object-fit:cover;box-shadow:0 1px 4px rgba(0,0,0,0.15)">"""
        }
        ICON_SVG_MAP[fabIcon]?.let { return it }
        return fabIcon
    }
